const data = $input.first().json;

if (!data.ok || !data.leads || data.leads.length === 0) {
  return [{ json: { hasLeads: false, html: '<p>No leads found today.</p>', count: 0, goldCount: 0 } }];
}

const leads = [...data.leads]
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 10);

const goldLeads = leads.filter(l => l.revenueTier === 'gold');
const otherLeads = leads.filter(l => l.revenueTier !== 'gold');

const renderLead = (l) => `
  <tr style="border-bottom:1px solid #eee">
    <td style="padding:8px;font-weight:bold">${l.title || 'Unnamed lead'}</td>
    <td style="padding:8px">${l.trade || ''}</td>
    <td style="padding:8px">${l.location || l.postcodeOutward || ''}</td>
    <td style="padding:8px">${l.estimatedValue || ''}</td>
    <td style="padding:8px;color:${l.revenueTier==='gold'?'#d97706':l.revenueTier==='worth-checking'?'#2563eb':'#6b7280'}">${l.revenueTier || ''}</td>
    <td style="padding:8px">${l.score || ''}</td>
  </tr>`;

const date = new Date().toLocaleDateString('en-GB', {weekday:'long', day:'numeric', month:'long'});

const html = `
<h2>JobFilter Lead Digest — ${date}</h2>
<p><strong>${data.count} leads</strong> found near ${data.outward} (${data.region}). ${data.lockedCount || 0} locked behind paywall.</p>

${goldLeads.length > 0 ? `<h3 style="color:#d97706">Gold Leads (${goldLeads.length})</h3>
<table style="border-collapse:collapse;width:100%">
  <tr style="background:#fef3c7;text-align:left"><th style="padding:8px">Title</th><th>Trade</th><th>Location</th><th>Value</th><th>Tier</th><th>Score</th></tr>
  ${goldLeads.map(renderLead).join('')}
</table>` : '<p>No gold leads today.</p>'}

${otherLeads.length > 0 ? `<h3>Other Leads (${otherLeads.length})</h3>
<table style="border-collapse:collapse;width:100%">
  <tr style="background:#f3f4f6;text-align:left"><th style="padding:8px">Title</th><th>Trade</th><th>Location</th><th>Value</th><th>Tier</th><th>Score</th></tr>
  ${otherLeads.map(renderLead).join('')}
</table>` : ''}

<p style="color:#6b7280;font-size:12px">Sources: ${(data.sources || []).join(', ')}</p>`;

return [{ json: { hasLeads: true, html, count: leads.length, goldCount: goldLeads.length } }];
